import inspect
if not hasattr(inspect, "getargspec"):
    inspect.getargspec = inspect.getfullargspec

import os
import sys
import secrets
import asyncio

# Add backend to path
sys.path.append(os.path.join(os.path.dirname(os.path.dirname(__file__)), "backend"))

from thor_requests.wallet import Wallet
from thor_requests.contract import Contract
import requests

BYTECODE = ""

def update_env_file(key: str, value: str):
    env_path = os.path.join("backend", ".env")
    if not os.path.exists(env_path):
        with open(env_path, "w") as f:
            f.write(f"{key}={value}\n")
        return
        
    with open(env_path, "r") as f:
        lines = f.readlines()
        
    replaced = False
    for i, line in enumerate(lines):
        if line.strip().startswith(f"{key}="):
            lines[i] = f"{key}={value}\n"
            replaced = True
            break
            
    if not replaced:
        lines.append(f"{key}={value}\n")
        
    with open(env_path, "w") as f:
        f.writelines(lines)

async def check_balance_api(address: str):
    try:
        r = requests.get(f"https://testnet.vechain.org/accounts/{address}", timeout=5)
        if r.status_code == 200:
            data = r.json()
            balance_vtho = int(data.get("energy", "0x0"), 16) / 1e18
            balance_vet = int(data.get("balance", "0x0"), 16) / 1e18
            return balance_vet, balance_vtho
    except Exception:
        pass
    return 0.0, 0.0

async def main():
    print("=" * 60)
    print("          CRAFTSHIELD VECHAIN TESTNET AUTO-SETUP")
    print("=" * 60)
    
    # 1. Generate new sponsor key
    new_private_key = "0x" + secrets.token_hex(32)
    wallet = Wallet.fromPrivateKey(bytes.fromhex(new_private_key[2:]))
    wallet_address = wallet.getAddress()
    
    print("\n[Step 1] Generated a fresh platform sponsor wallet:")
    print(f"  -> Private Key:  {new_private_key}")
    print(f"  -> Address:      {wallet_address}")
    
    # Update config immediately
    update_env_file("VECHAIN_SPONSOR_KEY", new_private_key)
    update_env_file("VECHAIN_NODE_URL", "https://testnet.vechain.org")
    print("OK: Updated 'backend/.env' with your new VECHAIN_SPONSOR_KEY.")
    
    print("\n[Step 2] Fund the wallet address:")
    print("  1. Open your browser and go to: https://faucet.vecha.in")
    print(f"  2. Paste this address: {wallet_address}")
    print("  3. Claim VET and VTHO.")
    print("  4. Return to this terminal once claimed successfully.")
    
    # Loop checking balance
    print("\nWaiting for faucet claim to register on-chain...")
    while True:
        vet, vtho = await check_balance_api(wallet_address)
        if vet > 0 or vtho > 0:
            print(f"\nSUCCESS: Received {vet:.2f} VET and {vtho:.2f} VTHO!")
            break
        print(".", end="", flush=True)
        await asyncio.sleep(3)
        
    # 2. Deploy Smart Contract
    print("\n[Step 3] Deploying DesignRegistry Smart Contract...")
    from app.services.blockchain import get_blockchain_connection
    conn = get_blockchain_connection()
    
    contract = Contract({
        "abi": [],
        "bytecode": bytes.fromhex(BYTECODE)
    })
    
    try:
        tx_receipt = conn.deploy(
            wallet=wallet,
            contract=contract
        )
        tx_id = tx_receipt.get("id") or tx_receipt.get("meta", {}).get("txID")
        print(f"Transaction sent! TxID: {tx_id}")
        print("Waiting for deployment block confirmation (takes ~10 seconds)...")
        
        receipt = conn.wait_for_tx_receipt(tx_id, timeout=30)
        if not receipt or receipt.get("reverted"):
            print("ERROR: Deployment failed or reverted.")
            return
            
        outputs = receipt.get("outputs", [])
        if outputs:
            contract_address = outputs[0].get("contractAddress")
            print(f"\nSUCCESS: DesignRegistry contract deployed to: {contract_address}")
            
            # Save contract address to env
            update_env_file("VECHAIN_CONTRACT_ADDRESS", contract_address)
            print("OK: Updated 'backend/.env' with VECHAIN_CONTRACT_ADDRESS.")
            
            print("\nSetup is 100% complete! Please restart your application server ('run_app.bat') to load the new config.")
        else:
            print("ERROR: Contract address not found in outputs.")
            
    except Exception as e:
        print(f"ERROR: Deployment failed: {e}")

if __name__ == "__main__":
    asyncio.run(main())
